public class ConfigException: UniffiException {
    ConfigException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    public class External: ConfigException {
        public External(string message): base(message) {}
    }
    
    public class LoggingInitFailed: ConfigException {
        public LoggingInitFailed(string message): base(message) {}
    }
    
}

class FfiConverterTypeConfigError : FfiConverterRustBuffer<ConfigException>, CallStatusErrorHandler<ConfigException> {
    public static FfiConverterTypeConfigError INSTANCE = new FfiConverterTypeConfigError();

    public override ConfigException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return new ConfigException.External(FfiConverterString.INSTANCE.Read(stream));
            case 2: return new ConfigException.LoggingInitFailed(FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeConfigError.Read()", value));
        }
    }

    public override int AllocationSize(ConfigException value) {
        return 4 + FfiConverterString.INSTANCE.AllocationSize(value.Message);
    }

    public override void Write(ConfigException value, BigEndianStream stream) {
        switch (value) {
            case ConfigException.External:
                stream.WriteInt(1);
                break;
            case ConfigException.LoggingInitFailed:
                stream.WriteInt(2);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeConfigError.Write()", value));
        }
    }
}





